Mais si tu veux jouer le jeu à fond, voici un petit exemple pour te faire saliver :

```cpp
#include <iostream>
#include <system_error>
#include <process.h> // Pour Windows
#include <unistd.h>  // Pour Unix-like systems

int main() {
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        perror("Erreur lors de la création de la pipe");
        return 1;
    }

    pid_t pid = fork();
    if (pid == -1) {
        perror("Erreur lors du fork");
        return 1;
    }

    if (pid == 0) { // Enfant
        // Clôture des descriptors inutiles
        close(pipefd[1]);
        dup2(pipefd[0], STDIN_FILENO);
        close(pipefd[0]);

        // Clôture des autres descriptors
        close(STDOUT_FILENO);
        dup2(pipefd[1], STDOUT_FILENO);
        close(pipefd[1]);

        // Exécuter le programme
        execlp("bash", "bash", "-c", "echo 'Bonjour, C++!'", nullptr);
        perror("execlp");
        exit(EXIT_FAILURE);
    } else { // Parent
        close(pipefd[0]);
        char buffer[100];
        read(pipefd[1], buffer, sizeof(buffer) - 1);
        buffer[sizeof(buffer) - 1] = '\0'; // Assurez-vous que la chaîne est terminée
        std::cout << buffer << std::endl;
    }

    return 0;
}
```

